    33→import com.opengamma.strata.product.TradeInfo;
    34→import com.opengamma.strata.product.common.SummarizerUtils;
    35→
    36→/**
    37→ * A trade in a CDS index.
    38→ * <p>
    39→ * An Over-The-Counter (OTC) trade in a {@link CdsIndex}.
    40→ * <p>
    41→ * A CDS index is a portofolio of single name credit default swaps. 
    42→ * The contract periodically pays fixed coupons to the index buyer until the expiry, 
    43→ * and in return, the index buyer receives the bond of a defaulted constituent legal entity for par.  
    44→ */
    45→@BeanDefinition
    46→public final class CdsIndexTrade
    47→    implements ProductTrade, ResolvableTrade<ResolvedCdsIndexTrade>, ImmutableBean, Serializable {
    48→
    49→  /**
    50→   * The additional trade information, defaulted to an empty instance.
    51→   * <p>
    52→   * This allows additional information to be attached to the trade.
    53→   */
    54→  @PropertyDefinition(validate = "notNull", overrideGet = true)
    55→  private final TradeInfo info;
    56→  /**
    57→   * The CDS index product that was agreed when the trade occurred.
    58→   * <p>
    59→   * The product captures the contracted financial details of the trade.
    60→   */
    61→  @PropertyDefinition(validate = "notNull", overrideGet = true)
    62→  private final CdsIndex product;
    63→  /**
    64→   * The upfront fee of the product.
    65→   * <p>
    66→   * This specifies a single amount payable by the buyer to the seller.
    67→   * Thus the sign must be compatible with the product Pay/Receive flag.
    68→   * <p>
    69→   * Some CDSs, especially legacy products, are traded at par and the upfront fee is not paid.
    70→   */
    71→  @PropertyDefinition(get = "optional")
    72→  private final AdjustablePayment upfrontFee;
    73→
    74→  //-------------------------------------------------------------------------
    75→  @Override
    76→  public CdsIndexTrade withInfo(PortfolioItemInfo info) {
    77→    return new CdsIndexTrade(TradeInfo.from(info), product, upfrontFee);
    78→  }
    79→
    80→  //-------------------------------------------------------------------------
    81→  @Override
    82→  public PortfolioItemSummary summarize() {
    83→    // 2Y Buy USD 1mm INDEX / 1.5% : 21Jan18-21Jan20
    84→    PeriodicSchedule paymentSchedule = product.getPaymentSchedule();
    85→    StringBuilder buf = new StringBuilder(96);
    86→    buf.append(SummarizerUtils.datePeriod(paymentSchedule.getStartDate(), paymentSchedule.getEndDate()));
    87→    buf.append(' ');
    88→    buf.append(product.getBuySell());
    89→    buf.append(' ');
    90→    buf.append(SummarizerUtils.amount(product.getCurrency(), product.getNotional()));
    91→    buf.append(' ');
    92→    buf.append(product.getCdsIndexId().getValue());
    93→    buf.append(" / ");
    94→    buf.append(SummarizerUtils.percent(product.getFixedRate()));
    95→    buf.append(" : ");
    96→    buf.append(SummarizerUtils.dateRange(paymentSchedule.getStartDate(), paymentSchedule.getEndDate()));
    97→    return SummarizerUtils.summary(this, ProductType.CDS_INDEX, buf.toString(), product.getCurrency());
    98→  }
