package com.opengamma.strata.product.credit;

import java.io.Serializable;
import java.util.Map;
import java.util.NoSuchElementException;
import java.util.Optional;

import org.joda.beans.Bean;
import org.joda.beans.ImmutableBean;
import org.joda.beans.JodaBeanUtils;
import org.joda.beans.MetaBean;
import org.joda.beans.MetaProperty;
import org.joda.beans.gen.BeanDefinition;
import org.joda.beans.gen.ImmutableDefaults;
import org.joda.beans.gen.PropertyDefinition;
import org.joda.beans.impl.direct.DirectFieldsBeanBuilder;
import org.joda.beans.impl.direct.DirectMetaBean;
import org.joda.beans.impl.direct.DirectMetaProperty;
import org.joda.beans.impl.direct.DirectMetaPropertyMap;

import com.opengamma.strata.basics.ReferenceData;
import com.opengamma.strata.basics.currency.Payment;
import com.opengamma.strata.product.ResolvedTrade;
import com.opengamma.strata.product.TradeInfo;

/**
 * A trade in a CDS index, resolved for pricing.
 * <p>
 * This is the resolved form of {@link CdsIndexTrade} and is the primary input to the pricers.
 * Applications will typically create a {@code ResolvedCdsIndexTrade} from a {@code CdsIndexTrade}
 * using {@link CdsIndexTrade#resolve(ReferenceData)}.
 * <p>
 * A {@code ResolvedCdsIndexTrade} is bound to data that changes over time, such as holiday calendars.
 * If the data changes, such as the addition of a new holiday, the resolved form will not be updated.
 * Care must be taken when placing the resolved form in a cache or persistence layer.
 */
@BeanDefinition
public final class ResolvedCdsIndexTrade
    implements ResolvedTrade, ImmutableBean, Serializable {

  /**
   * The additional trade information, defaulted to an empty instance.
   * <p>
   * This allows additional information to be attached to the trade.
   */
  @PropertyDefinition(validate = "notNull", overrideGet = true)
  private final TradeInfo info;
  /**
   * The resolved CDS index product.
   * <p>
   * The product captures the contracted financial details of the trade.
   */
  @PropertyDefinition(validate = "notNull", overrideGet = true)
  private final ResolvedCdsIndex product;
  /**
   * The upfront fee of the product.
   * <p>
   * This specifies a single amount payable by the buyer to the seller
   * Thus the sign must be compatible with the product Pay/Receive flag.
   */
  @PropertyDefinition(get = "optional")
  private final Payment upfrontFee;

  //-------------------------------------------------------------------------
  @ImmutableDefaults
  private static void applyDefaults(Builder builder) {
    builder.info = TradeInfo.empty();
  }

  //-------------------------------------------------------------------------
  /**
   * Reduce this instance to {@code ResolvedCdsTrade}.
   * <p>
   * The resultant object is used for pricing CDS index trades under the homogeneous pool assumption on constituent  
   * credit curves. 
   * 
   * @return the CDS trade
   */
  public ResolvedCdsTrade toSingleNameCds() {
    return ResolvedCdsTrade.builder()
        .product(product.toSingleNameCds())
        .info(info)
        .upfrontFee(upfrontFee)
        .build();
  }

  //------------------------- AUTOGENERATED START -------------------------
  /**
   * The meta-bean for {@code ResolvedCdsIndexTrade}.
   * @return the meta-bean, not null
   */
  public static ResolvedCdsIndexTrade.Meta meta() {
    return ResolvedCdsIndexTrade.Meta.INSTANCE;
  }

